package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithTrim() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat trimmedFormat = format.withTrim();

        assertNotNull(trimmedFormat);
        assertTrue(trimmedFormat.getTrim());
        // Original format should not be changed
        assertFalse(format.getTrim());
        // withTrim(true) should be equivalent to withTrim()
        CSVFormat explicitTrim = format.withTrim(true);
        assertEquals(explicitTrim, trimmedFormat);
    }
}
